import SourceState from"./State.js";import TileImage from"./TileImage.js";import{getTileSetInfo}from"./ogcTileUtil.js";class OGCMapTile extends TileImage{constructor(t){super({attributions:t.attributions,cacheSize:t.cacheSize,crossOrigin:t.crossOrigin,imageSmoothing:t.imageSmoothing,projection:t.projection,reprojectionErrorThreshold:t.reprojectionErrorThreshold,state:SourceState.LOADING,tileLoadFunction:t.tileLoadFunction,wrapX:void 0===t.wrapX||t.wrapX,transition:t.transition});t={url:t.url,projection:this.getProjection(),mediaType:t.mediaType,context:t.context||null};getTileSetInfo(t).then(this.handleTileSetInfo_.bind(this)).catch(this.handleError_.bind(this))}handleTileSetInfo_(t){this.tileGrid=t.grid,this.setTileUrlFunction(t.urlFunction,t.urlTemplate),this.setState(SourceState.READY)}handleError_(t){console.error(t),this.setState(SourceState.ERROR)}}export default OGCMapTile;